// CefasServer is the server API for Cefas service.
// All implementations must embed UnimplementedCefasServer
// for forward compatibility.
type CefasServer interface {
	// Schema management.
	CreateTable(context.Context, *CreateTableRequest) (*CreateTableResponse, error)
	DescribeTable(context.Context, *DescribeTableRequest) (*DescribeTableResponse, error)
	ListTables(context.Context, *ListTablesRequest) (*ListTablesResponse, error)
	DropTable(context.Context, *DropTableRequest) (*DropTableResponse, error)
	// DynamoDB Streams discovery surface.
	ListStreams(context.Context, *ListStreamsRequest) (*ListStreamsResponse, error)
	DescribeStream(context.Context, *DescribeStreamRequest) (*DescribeStreamResponse, error)
	GetShardIterator(context.Context, *GetShardIteratorRequest) (*GetShardIteratorResponse, error)
	GetRecords(context.Context, *GetRecordsRequest) (*GetRecordsResponse, error)
	// TTL configuration. The reaper already honours TableDescriptor.TTLAttribute;
	// these RPCs only mutate the catalog entry.
	UpdateTimeToLive(context.Context, *UpdateTimeToLiveRequest) (*UpdateTimeToLiveResponse, error)
	DescribeTimeToLive(context.Context, *DescribeTimeToLiveRequest) (*DescribeTimeToLiveResponse, error)
	// Item operations.
	PutItem(context.Context, *PutItemRequest) (*PutItemResponse, error)
	GetItem(context.Context, *GetItemRequest) (*GetItemResponse, error)
	UpdateItem(context.Context, *UpdateItemRequest) (*UpdateItemResponse, error)
	DeleteItem(context.Context, *DeleteItemRequest) (*DeleteItemResponse, error)
	// Bulk operations.
	BatchWriteItem(context.Context, *BatchWriteItemRequest) (*BatchWriteItemResponse, error)
	BatchGetItem(context.Context, *BatchGetItemRequest) (*BatchGetItemResponse, error)
	// Atomic multi-item transactions. v1 ships single-shard, single-table
	// atomicity via one pebble.Batch + one raft entry. Multi-shard 2PC is
	// out of scope.
	TransactWriteItems(context.Context, *TransactWriteItemsRequest) (*TransactWriteItemsResponse, error)
	TransactGetItems(context.Context, *TransactGetItemsRequest) (*TransactGetItemsResponse, error)
	// Query and scan stream rows so the server never materialises an
	// unbounded result set in memory.
	Query(*QueryRequest, grpc.ServerStreamingServer[Item]) error
	Scan(*ScanRequest, grpc.ServerStreamingServer[Item]) error
	SpatialQuery(*SpatialQueryRequest, grpc.ServerStreamingServer[Item]) error
	// SQL surface — single statement per call. Affected_rows is set for
	// DDL/DML; rows is set for SELECT.
	Sql(context.Context, *SqlRequest) (*SqlResponse, error)
	// Cluster surface (no-ops in single-node mode).
	ClusterStatus(context.Context, *ClusterStatusRequest) (*ClusterStatusResponse, error)
	AddVoter(context.Context, *AddVoterRequest) (*AddVoterResponse, error)
	RemoveServer(context.Context, *RemoveServerRequest) (*RemoveServerResponse, error)
	PlanPlacement(context.Context, *PlanPlacementRequest) (*PlanPlacementResponse, error)
	ApplyPlacement(context.Context, *ApplyPlacementRequest) (*ApplyPlacementResponse, error)
	FinalizeSplit(context.Context, *FinalizeSplitRequest) (*FinalizeSplitResponse, error)
	FinalizeRangeMove(context.Context, *FinalizeRangeMoveRequest) (*FinalizeRangeMoveResponse, error)
	// Change Data Capture stream. Subscribers receive every committed
	// write in raft log order. Slow consumers may miss events when their
	// server-side ring buffer fills; at-least-once-in-order for live
	// consumers.
	StreamChanges(*StreamChangesRequest, grpc.ServerStreamingServer[ChangeEvent]) error
	// Snapshot administration (PITR foundation).
	ListSnapshots(context.Context, *ListSnapshotsRequest) (*ListSnapshotsResponse, error)
	// Storage administration.
	Compact(context.Context, *CompactRequest) (*CompactResponse, error)
	// Admin-named backups (pebble.Checkpoint of the live keyspace,
	// catalogued under cefas/admin/backups/<name>).
	CreateBackup(context.Context, *CreateBackupRequest) (*CreateBackupResponse, error)
	ListBackups(context.Context, *ListBackupsRequest) (*ListBackupsResponse, error)
	DeleteBackup(context.Context, *DeleteBackupRequest) (*DeleteBackupResponse, error)
	ApplyBackupRetention(context.Context, *ApplyBackupRetentionRequest) (*ApplyBackupRetentionResponse, error)
	RestoreTableFromBackup(context.Context, *RestoreTableFromBackupRequest) (*RestoreTableFromBackupResponse, error)
	// Plugin introspection.
	ListPlugins(context.Context, *ListPluginsRequest) (*ListPluginsResponse, error)
	DescribePlugin(context.Context, *DescribePluginRequest) (*DescribePluginResponse, error)
	// Plugin-backed index lifecycle (#158, #159, #160).
	CreateIndex(context.Context, *CreateIndexRequest) (*CreateIndexResponse, error)
	DescribeIndex(context.Context, *DescribeIndexRequest) (*DescribeIndexResponse, error)
	RebuildIndex(context.Context, *RebuildIndexRequest) (*RebuildIndexResponse, error)
	// Planner observability + top-K (#163, #164).
	Explain(context.Context, *ExplainRequest) (*ExplainResponse, error)
	TopK(context.Context, *TopKRequest) (*TopKResponse, error)
	// Cohort ops backed by the roaring + HLL plugins (#165, #166).
	CohortCreate(context.Context, *CohortCreateRequest) (*CohortCreateResponse, error)
	CohortEstimate(context.Context, *CohortEstimateRequest) (*CohortEstimateResponse, error)
	// Audience ops (#167-#170).
	GeoAudience(*GeoAudienceRequest, grpc.ServerStreamingServer[Item]) error
	Dedup(context.Context, *DedupRequest) (*DedupResponse, error)
	FreqCap(context.Context, *FreqCapRequest) (*FreqCapResponse, error)
	Aggregate(context.Context, *AggregateRequest) (*AggregateResponse, error)
	// Rerank applies the MMR diversification operator to a candidate
	// set (issue #244).
	Rerank(context.Context, *RerankRequest) (*RerankResponse, error)
	// Pipeline operators (#247, #248).
	Recommend(context.Context, *RecommendRequest) (*RecommendResponse, error)
	NextBestAction(context.Context, *NextBestActionRequest) (*NextBestActionResponse, error)
	RecordReward(context.Context, *RecordRewardRequest) (*RecordRewardResponse, error)
	GetDecision(context.Context, *GetDecisionRequest) (*GetDecisionResponse, error)
	// ===== Bandit (issue #246) =====
	BanditCreate(context.Context, *BanditCreateRequest) (*BanditCreateResponse, error)
	BanditSample(context.Context, *BanditSampleRequest) (*BanditSampleResponse, error)
	BanditReward(context.Context, *BanditRewardRequest) (*BanditRewardResponse, error)
	BanditDescribe(context.Context, *BanditDescribeRequest) (*BanditDescribeResponse, error)
	mustEmbedUnimplementedCefasServer()
}

